(()=>{'use strict';
const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,'').replace(/[^0-9.\-]/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH');
const E=s=>T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
function activeName(){return T($('.tab.on')?.textContent)||'ถอดของ Pro'}
function rowsFromTable(){return $$('#table tbody tr').map(tr=>[...tr.children].map(td=>{const i=td.querySelector('input');return i?T(i.value):T(td.innerText)})).filter(r=>r.length&&r.join('').trim()&&!/ไม่มีข้อมูล|โหลดไฟล์|เลือก “ส่งให้ร้าน”/.test(r.join(' ')))}
function headsFromTable(){return $$('#table thead th').map(th=>T(th.innerText)).filter(Boolean)}
function meta(){return [['ฟังก์ชัน',activeName()],['วันที่พิมพ์',new Date().toLocaleDateString('th-TH',{timeZone:'Asia/Bangkok',day:'numeric',month:'long',year:'numeric'})],['วันที่',T($('#datesText')?.textContent).replace(/^วันที่:\s*/, '')||'ทั้งหมด'],['PS',T($('#psText')?.textContent).replace(/^PS:\s*/, '')||'ทั้งหมด'],['ส่งให้ร้าน',T($('#sendText')?.textContent)||'-']]}
function makeGeneric(title,heads,rows){if(!rows.length)return alert('ไม่มีข้อมูลสำหรับปริ้นในหน้า '+title);const m=meta().map(([k,v])=>`<div contenteditable="true"><b>${E(k)}:</b> ${E(v)}</div>`).join('');const h=heads.map(x=>`<th>${E(x)}</th>`).join('');const b=rows.map((r,i)=>`<tr><td class="c">${i+1}</td>${r.map(x=>`<td contenteditable="true">${E(x)}</td>`).join('')}</tr>`).join('');openPrint(`<section class="printPage"><h1 contenteditable="true">${E(title)}</h1><div class="metaGrid">${m}</div><table><thead><tr><th style="width:36px">#</th>${h}</tr></thead><tbody>${b}</tbody></table></section>`)}
function makeReceipt(){const rows=rowsFromTable(),heads=headsFromTable();makeGeneric('ใบส่งสินค้า / ใบเสร็จรับเงิน',heads,rows)}
function openPrint(html){let st=$('#ctxPrintCss');if(!st){st=document.createElement('style');st.id='ctxPrintCss';st.textContent='.printOverlay{position:fixed;inset:0;background:#fff;z-index:9999;overflow:auto;color:#000}.printBar{position:sticky;top:0;background:#fff;border-bottom:1px solid #000;padding:8px;display:flex;justify-content:space-between}.printPage{font-family:system-ui,-apple-system,"Segoe UI",Tahoma,sans-serif;width:194mm;min-height:281mm;margin:8px auto;padding:10mm;background:#fff}.printPage h1{font-size:24px;margin:0 0 12px;border-bottom:3px solid #111;padding-bottom:8px}.metaGrid{display:grid;grid-template-columns:1fr 1fr;gap:8px 16px;border:1px solid #111;padding:8px;margin-bottom:12px}.printPage table{width:100%;border-collapse:collapse;font-size:12px}.printPage th,.printPage td{border:1px solid #111;padding:5px}.c{text-align:center}[contenteditable="true"]:focus{outline:1px dashed #2563eb;background:#eff6ff}@media print{body>*:not(.printOverlay){display:none!important}.printBar{display:none!important}.printOverlay{position:static}.printPage{width:auto;min-height:auto;margin:0;padding:0}}';document.head.appendChild(st)}const ov=document.createElement('div');ov.className='printOverlay';ov.innerHTML=`<div class="printBar"><b>ตรวจ/แก้ไขก่อนปริ้น</b><span><button onclick="this.closest('.printOverlay').remove()">ปิด</button> <button onclick="window.print()">ปริ้น</button></span></div>${html}`;document.body.appendChild(ov)}
function ctxPrint(){const name=activeName(),heads=headsFromTable(),rows=rowsFromTable();if(name==='ใบส่งร้านจริง')return makeReceipt();return makeGeneric(name,heads,rows)}
function bind(){const b=$('#prepPrint');if(!b)return false;b.onclick=ctxPrint;return true}
function boot(){if(!bind())setTimeout(boot,300)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();